var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배.","JPN":"先輩。","ENG":"Shiyoon...","TWN":"前輩。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"묻고 싶은 게 있어.","JPN":"聞きたいことがあるの。","ENG":"I have something to ask you.","TWN":"我有事情想問你。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"뭐죠? 미나 양.","JPN":"何でしょう、ミナさん。","ENG":"What is it, Mina?","TWN":"是什麼？米娜小姐。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"리플레이서 비숍이 마지막에 한 말...... 무슨 뜻이었을까......?","JPN":"リプレイサー・ビショップの最期の言葉……どういう意味だったのかな……？","ENG":"That last thing the Replacer Bishop said... What do you think she meant by that?","TWN":"克隆大主教最後說的話……是什麼意思啊？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"우린 분명 적이었을 텐데...... 어째서 목숨까지 버려가면서 그런 일을 한 거지?","JPN":"私たちは敵対してたはずなのに……どうして命を捨ててまであんなことを？","ENG":"We were enemies to each other. Why did she have to throw away her life to do something like that?","TWN":"我們明明是敵人……為什麼她不惜放棄自己的生命，也要做出那樣的事？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"글쎄요......","JPN":"どうでしょうね……","ENG":"Well...","TWN":"這個嘛……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"원래 리플레이서 재생체에게 모체라는 것은 단순히 자신의 설계 기반을 제공한 자를 일컫는 기술적인 단어였을 겁니다.","JPN":"元々リプレイサー再生体にとって「母体」というものは、\\n単に自分の設計基盤を提供した者を指す技術的な単語だったのでしょうね。","ENG":"To regenerated Replacers, \\"source\\" was probably just a technical term referring to the person who provided the base information of their overall design.","TWN":"原本克隆集團再生體的母體，單純是用來稱呼提供設計基盤者的技術用語。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만...... 어떻게 보면 그 강력한 힘과는 별개로 그녀들은 사실 이 세상에 태어난 지 얼마 되지 않은 어린 존재들이라고 할 수도 있죠.","JPN":"でも……ある意味、その強力な力にかかわらず、\\n彼女たちはこの世に生まれたての幼い存在とも言えます。","ENG":"However, apart from their superhuman strength, they were like young children newly born into the world.","TWN":"然而…… 換個角度來看，她們雖然擁有強大的力量，事實上卻可以說是剛誕生在世上不久的年幼存在。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그런 그녀들이 자신의 모체에게 단순한 설계 제공자의 역할을 넘어 <color=#ffd34c>어머니</color>로서의 애정을 원했다고 해도 이상한 일은 아니겠죠.","JPN":"そんな彼女たちが自分の母体に対し、単に設計提供者の役割以上の、\\n<color=#ffd34c>母</color>としての愛情を求めたとしても、不思議なことではありませんね。","ENG":"Maybe it was natural that what they expected from their sources gradually developed from mere compositional information to <color=#ffd34c>maternal love</color>.","TWN":"這樣的她們沒有把母體當成單純的設計提供者，而是視為<color=#ffd34c>母親</color>來獲得愛，也不是什麼奇怪的事情吧。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"다른 재생체들은 모체와 관련된 생존자들이 없었으니까 그런 욕구가 강하게 발현되지 않았겠지만......","JPN":"他の再生体には、母体と関わったことのある生存者がおらず、\\nそういった欲求が強く現れていないでしょうけど……","ENG":"As for other regenerated Replacers, such a desire wasn't manifested so strongly because they didn't have any survivors related with their sources.","TWN":"因為其他再生體沒有與母體相關的生存者，所以這種欲望沒有強烈地表現出來……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"비숍의 경우는 다르죠.","JPN":"ビショップの場合は別ですね。","ENG":"But it was different in Bishop's case.","TWN":"不過大主教的情況卻不一樣。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"모체와 감정적으로 강력하게 연결된...... 실제로 살아있는 존재가 있었으니까요.","JPN":"母体と強い結びつきがある……実在する人間がいましたから。","ENG":"She had someone that was still alive who had a strong connection to her source.","TWN":"因為有個情感上與母體強烈連接……真實活著的人。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이건 제 추측일 뿐이지만...... 어쩌면 비숍은 미나 양을 어머니의 친구로 여겼을지도 모릅니다.","JPN":"これは僕の推測でしかありませんが……\\nひょっとすると、ビショップは、ミナさんのことをお母さんの友人として受け止めていたのかもしれません。","ENG":"This is only a guess, but Bishop might have considered you a friend of her mother;","TWN":"雖然這只是我的猜測……但大主教大概把米娜小姐當作自己母親的朋友了。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이 세상에 유일하게 존재하는 혈육...... 가족으로 말이죠.","JPN":"この世に存在する、たった一人の……家族として。","ENG":"the last person left in this world who she could feel connected to... A family.","TWN":"當成是這世上唯一存在的親人……也就是家人。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"선배......","JPN":"先輩……","ENG":"Shiyoon...","TWN":"前輩……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나......","JPN":"私……","ENG":"I...","TWN":"我……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"가세요, 미나 양.","JPN":"行ってください、ミナさん。","ENG":"Go, Mina.","TWN":"去吧，米娜小姐。"},"stage":{"bg":"MAINSTREAM_5508011","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};